//! Benchmarks for data serialization hot paths.
//!
//! Measures throughput of buffer creation, data pack/unpack, and
//! byte object operations.
//!
//! Run with:
//! ```bash
//! cargo bench --bench data_serialization_bench
//! ```

use criterion::{Criterion, black_box, criterion_group, criterion_main};
use pmix::data_serialization::*;

// ─────────────────────────────────────────────────────────────────────────────
// Buffer lifecycle benchmarks
// ─────────────────────────────────────────────────────────────────────────────

fn bench_buffer_create_release(c: &mut Criterion) {
    c.bench_function("buffer_create_release", |b| {
        b.iter(|| {
            let mut buf = data_buffer_create().unwrap();
            data_buffer_release(&mut buf);
        })
    });
}

// ─────────────────────────────────────────────────────────────────────────────
// ByteObject benchmarks
// ─────────────────────────────────────────────────────────────────────────────

fn bench_byteobject_from_vec_small(c: &mut Criterion) {
    c.bench_function("byteobject_from_vec_64B", |b| {
        let data = vec![0xABu8; 64];
        b.iter(|| {
            let _obj = PmixByteObject::from(black_box(data.clone()));
        })
    });
}

fn bench_byteobject_from_vec_large(c: &mut Criterion) {
    c.bench_function("byteobject_from_vec_4KB", |b| {
        let data = vec![0xABu8; 4096];
        b.iter(|| {
            let _obj = PmixByteObject::from(black_box(data.clone()));
        })
    });
}

fn bench_byteobject_as_slice(c: &mut Criterion) {
    c.bench_function("byteobject_as_slice_256B", |b| {
        let obj = PmixByteObject::from(vec![0xABu8; 256]);
        b.iter(|| {
            black_box(obj.as_slice());
        })
    });
}

// ─────────────────────────────────────────────────────────────────────────────
// Load/Unload benchmarks (no PMIx_Init needed)
// ─────────────────────────────────────────────────────────────────────────────

fn bench_load_unload_small(c: &mut Criterion) {
    c.bench_function("load_unload_64B", |b| {
        let payload = PmixByteObject::from(vec![0xABu8; 64]);
        b.iter(|| {
            let mut buf = data_buffer_create().unwrap();
            data_load(&buf, &payload).unwrap();
            let _out = data_unload(&buf).unwrap();
            data_buffer_release(&mut buf);
        })
    });
}

fn bench_load_unload_large(c: &mut Criterion) {
    c.bench_function("load_unload_4KB", |b| {
        let payload = PmixByteObject::from(vec![0xABu8; 4096]);
        b.iter(|| {
            let mut buf = data_buffer_create().unwrap();
            data_load(&buf, &payload).unwrap();
            let _out = data_unload(&buf).unwrap();
            data_buffer_release(&mut buf);
        })
    });
}

fn bench_load_unload_64KB(c: &mut Criterion) {
    c.bench_function("load_unload_64KB", |b| {
        let payload = PmixByteObject::from(vec![0xABu8; 65536]);
        b.iter(|| {
            let mut buf = data_buffer_create().unwrap();
            data_load(&buf, &payload).unwrap();
            let _out = data_unload(&buf).unwrap();
            data_buffer_release(&mut buf);
        })
    });
}

// ─────────────────────────────────────────────────────────────────────────────
// Buffer growth benchmark — simulates packing many values via load
// ─────────────────────────────────────────────────────────────────────────────

fn bench_buffer_grow(c: &mut Criterion) {
    c.bench_function("buffer_grow_100x64B", |b| {
        b.iter(|| {
            let mut buf = data_buffer_create().unwrap();
            for _ in 0..100 {
                let payload = PmixByteObject::from(vec![0xABu8; 64]);
                data_load(&buf, &payload).unwrap();
            }
            data_buffer_release(&mut buf);
        })
    });
}

// ─────────────────────────────────────────────────────────────────────────────
// Buffer bytes_used/bytes_allocated queries
// ─────────────────────────────────────────────────────────────────────────────

fn bench_buffer_queries(c: &mut Criterion) {
    c.bench_function("buffer_bytes_used_query", |b| {
        let payload = PmixByteObject::from(vec![0xABu8; 256]);
        let mut buf = data_buffer_create().unwrap();
        data_load(&buf, &payload).unwrap();
        b.iter(|| {
            black_box(buf.bytes_used());
            black_box(buf.bytes_allocated());
        });
        data_buffer_release(&mut buf);
    });
}

// ─────────────────────────────────────────────────────────────────────────────
// Criteria
// ─────────────────────────────────────────────────────────────────────────────

fn benchmark_suite(c: &mut Criterion) {
    bench_buffer_create_release(c);
    bench_byteobject_from_vec_small(c);
    bench_byteobject_from_vec_large(c);
    bench_byteobject_as_slice(c);
    bench_load_unload_small(c);
    bench_load_unload_large(c);
    bench_load_unload_64KB(c);
    bench_buffer_grow(c);
    bench_buffer_queries(c);
}

criterion_group!(benches, benchmark_suite);
criterion_main!(benches);

use std::env;
use std::path::{Path, PathBuf};

/// Discover PMIx install prefix.
/// Order: PMIX_PREFIX → PMIX_INCLUDE_DIR/PMIX_LIB_DIR parents → common prefixes → /usr
fn discover_pmix() -> (PathBuf, PathBuf) {
    println!("cargo:rerun-if-env-changed=PMIX_PREFIX");
    println!("cargo:rerun-if-env-changed=PMIX_INCLUDE_DIR");
    println!("cargo:rerun-if-env-changed=PMIX_LIB_DIR");

    if let Ok(prefix) = env::var("PMIX_PREFIX") {
        let prefix = PathBuf::from(prefix);
        return (prefix.join("include"), prefix.join("lib"));
    }

    let include = env::var("PMIX_INCLUDE_DIR").ok().map(PathBuf::from);
    let lib = env::var("PMIX_LIB_DIR").ok().map(PathBuf::from);
    if let (Some(inc), Some(lib)) = (include, lib) {
        return (inc, lib);
    }

    // Portable fallbacks only — no user-home defaults.
    let candidates = ["/usr", "/usr/local", "/opt/pmix", "/opt/prrte"];
    for c in candidates {
        let p = Path::new(c);
        let inc = p.join("include");
        let lib = p.join("lib");
        // Accept either pmix.h at include/pmix.h or include present with libpmix
        if inc.join("pmix.h").exists()
            || (lib.exists() && (lib.join("libpmix.so").exists() || lib.join("libpmix.a").exists()))
        {
            return (inc, lib);
        }
    }

    // Last resort: /usr layout (bindgen may still fall back to pre-generated bindings)
    (PathBuf::from("/usr/include"), PathBuf::from("/usr/lib"))
}

fn main() {
    let (include_dir, lib_dir) = discover_pmix();

    println!("cargo:rustc-link-search=native={}", lib_dir.display());
    println!("cargo:rustc-link-arg=-Wl,-rpath,{}", lib_dir.display());
    println!("cargo:rustc-link-lib=pmix");
    println!("cargo:rerun-if-changed=wrapper.h");

    let src_path = PathBuf::from("src").join("bindings.rs");
    let out_path = PathBuf::from(env::var("OUT_DIR").unwrap()).join("bindings.rs");

    let mut builder = bindgen::Builder::default()
        .generate_comments(false)
        .rustified_enum(".*")
        .header("wrapper.h")
        .parse_callbacks(Box::new(bindgen::CargoCallbacks::new()));

    if include_dir.exists() {
        builder = builder.clang_arg(format!("-I{}", include_dir.display()));
    }

    match builder.generate() {
        Ok(bindings) => {
            println!("cargo:warning=bindgen succeeded — generating fresh PMIx bindings");
            bindings
                .write_to_file(&out_path)
                .expect("Failed to write bindings to OUT_DIR");
            // Keep offline fallback in-tree for contributors without libclang
            let _ = std::fs::copy(&out_path, &src_path);
        }
        Err(e) => {
            println!(
                "cargo:warning=bindgen failed ({e}) — using pre-generated src/bindings.rs as fallback"
            );
            if src_path.exists() {
                std::fs::copy(&src_path, &out_path)
                    .expect("Failed to copy fallback bindings to OUT_DIR");
            } else {
                panic!(
                    "bindgen failed and no pre-generated src/bindings.rs found.\n\
                     Set PMIX_PREFIX (or PMIX_INCLUDE_DIR + PMIX_LIB_DIR), install libclang-dev,\n\
                     or provide src/bindings.rs."
                );
            }
        }
    }

    println!("cargo:rerun-if-changed={}", src_path.display());
}

//! Minimal PMIx client example: init → put → commit → fence → get → finalize.
//!
//! ```text
//! cargo run --example client_minimal
//! ```
//!
//! Usually needs a PMIx runtime (e.g. `prterun -n 1 target/debug/examples/client_minimal`).
//! Without a DVM, `init` may fail — that is expected in bare `cargo run`.

use std::ffi::CString;

fn main() {
    println!("pmix-rs client_minimal");

    let ctx = match pmix::init(None) {
        Ok(c) => c,
        Err(e) => {
            eprintln!("pmix::init failed (need prterun/DVM?): {e:?}");
            return;
        }
    };

    let key = CString::new("client_minimal_key").expect("key");
    let mut value = pmix::PmixValueBuilder::new()
        .string("hello from client_minimal")
        .expect("string")
        .build()
        .expect("build");

    if let Err(e) = pmix::put_value(pmix::PmixScope::Global.to_raw(), &key, &mut value) {
        eprintln!("put_value failed: {e:?}");
        return;
    }
    if let Err(e) = pmix::commit() {
        eprintln!("commit failed: {e:?}");
        return;
    }
    if let Err(e) = pmix::fence(ctx.get_proc(), None) {
        eprintln!("fence failed: {e:?}");
        return;
    }

    match pmix::get_value(ctx.get_proc(), b"client_minimal_key\0", None) {
        Ok(_) => println!("get_value ok"),
        Err(e) => println!("get_value: {e:?} (ok without full DVM in some envs)"),
    }

    // Context drop finalizes
    println!("client_minimal done");
}

//! Sophisticated data packing / unpacking example.
//!
//! Demonstrates packing heterogeneous data (i32 + string + bytes) into a
//! PMIx data buffer, unloading for "transport", loading into a new buffer,
//! and unpacking the values.
//!
//! This is more sophisticated than basic put/get because it shows:
//! - Multiple data types in one buffer
//! - Buffer unload/load (for sending over the wire or storing)
//! - Proper count handling for unpack
//! - Roundtrip verification
//!
//! Run with: cargo run --example data_packing

use pmix::{PmixDataType, data_serialization::*};

fn main() {
    println!("PMIx sophisticated data packing example");

    // === Sender side ===
    let mut buf = data_buffer_create().expect("failed to create data buffer");

    // Pack an i32
    let int_val: i32 = 42;
    let packed_int =
        data_pack(None, &buf, &int_val, 1, PmixDataType::Int32).expect("failed to pack i32");
    println!("Packed {} i32 value(s)", packed_int);

    // Pack a string (as PMIX_STRING)
    let msg = "hello from packed data";
    let packed_str =
        data_pack(None, &buf, &msg, 1, PmixDataType::String).expect("failed to pack string");
    println!("Packed {} string value(s)", packed_str);

    // Pack some raw bytes (as array of uint8)
    let bytes: Vec<u8> = vec![0xde, 0xad, 0xbe, 0xef];
    let packed_bytes = data_pack(None, &buf, &bytes, bytes.len() as i32, PmixDataType::Uint8)
        .expect("failed to pack bytes");
    println!("Packed {} byte(s)", packed_bytes);

    // Unload the buffer into a byte object (simulates transport / storage)
    let payload = data_unload(&buf).expect("failed to unload buffer");
    println!("Unloaded buffer -> {} bytes payload", payload.size());

    // Release the original buffer
    data_buffer_release(&mut buf);

    // === Receiver side (simulating another process or later time) ===
    let mut buf2 = data_buffer_create().expect("failed to create receiver buffer");
    data_load(&buf2, &payload).expect("failed to load payload into buffer");

    // Unpack the i32 (count starts as max we expect)
    let mut out_int: i32 = 0;
    let mut count: i32 = 1;
    let unpacked_int = data_unpack(None, &buf2, &mut out_int, &mut count, PmixDataType::Int32)
        .expect("failed to unpack i32");
    println!("Unpacked {} i32: {}", unpacked_int, out_int);

    // Unpack the string
    let mut out_str: String = String::new();
    let mut count: i32 = 1;
    let unpacked_str = data_unpack(None, &buf2, &mut out_str, &mut count, PmixDataType::String)
        .expect("failed to unpack string");
    println!("Unpacked {} string: {}", unpacked_str, out_str);

    // Unpack the bytes (we know how many)
    let mut out_bytes: Vec<u8> = vec![0u8; 4];
    let mut count: i32 = 4;
    let unpacked_bytes = data_unpack(None, &buf2, &mut out_bytes, &mut count, PmixDataType::Uint8)
        .expect("failed to unpack bytes");
    println!("Unpacked {} bytes: {:02x?}", unpacked_bytes, out_bytes);

    // Verify roundtrip
    assert_eq!(out_int, 42);
    assert_eq!(out_str, "hello from packed data");
    assert_eq!(out_bytes, vec![0xde, 0xad, 0xbe, 0xef]);
    println!("Roundtrip verification successful!");

    // Clean up
    data_buffer_release(&mut buf2);

    println!("Data packing example completed successfully");
}

//! Minimal PMIx server example: server_init → (idle) → server_finalize.
//!
//! ```text
//! cargo run --example server_minimal
//! ```
//!
//! Uses a default [`PmixServerModule`] (all callbacks `None`). Real RMs set
//! the callbacks they implement before calling `server_init`.

use pmix::InfoBuilder;
use pmix::server::{PmixServerModule, server_finalize, server_init_minimal};

fn main() {
    println!("pmix-rs server_minimal");

    let module = PmixServerModule::default();
    let info = InfoBuilder::new().build();

    let handle = match server_init_minimal(Some(&module)) {
        Ok(h) => h,
        Err(e) => {
            // Fall back to full server_init with empty info for environments
            // where the minimal path differs.
            match pmix::server::server_init(Some(&module), &info) {
                Ok(h) => h,
                Err(e2) => {
                    eprintln!("server_init failed: {e:?} / {e2:?}");
                    return;
                }
            }
        }
    };

    println!("server initialized (no clients attached in this smoke example)");
    // Real servers block here serving clients.

    match server_finalize(handle) {
        Ok(()) => println!("server_finalize ok"),
        Err(e) => eprintln!("server_finalize: {e:?}"),
    }

    println!("server_minimal done");
}

//! Very simple fence example.
//
//! cargo run --example simple_fence

fn main() {
    println!("PMIx simple fence example");

    let ctx = pmix::init(None).expect("init failed");

    // Just fence
    let result = pmix::fence(ctx.get_proc(), None);
    match result {
        Ok(()) => println!("fence succeeded"),
        Err(e) => println!("fence status: {:?}", e),
    }

    // Optional: fence with empty info
    let info = pmix::info::empty();
    let _ = pmix::fence(ctx.get_proc(), Some(info));

    println!("Simple fence example done");
}

//! Very simple example using put / get / commit / fence.
//!
//! Run with: cargo run --example simple_put_get
//! (Usually requires a PMIx daemon via prterun or prte)

use std::ffi::CString;

fn main() {
    println!("PMIx Rust simple put/get/commit/fence example");

    // Init (Context finalizes on drop)
    let ctx = pmix::init(None).expect("pmix::init failed");

    // Key (null terminated for get)
    let key = CString::new("simple_example_key").unwrap();

    // Build a string value
    let mut value = pmix::PmixValueBuilder::new()
        .string("hello from the pmix rust example")
        .expect("string value")
        .build()
        .expect("build value");

    // Put the value using Global scope
    pmix::put_value(pmix::PmixScope::Global.to_raw(), &key, &mut value).expect("put_value failed");

    // Commit the puts
    pmix::commit().expect("commit failed");

    // Fence for visibility
    pmix::fence(ctx.get_proc(), None).expect("fence failed");

    // Try to get it back
    match pmix::get_value(ctx.get_proc(), b"simple_example_key\0", None) {
        Ok(_val) => println!("Got value successfully via get_value"),
        Err(e) => {
            println!(
                "get_value status (expected without full DVM in some envs): {:?}",
                e
            );
        }
    }

    println!("Simple put/get/commit/fence example finished");
}

//! Minimal PMIx tool example: tool_init → optional attach → query path → finalize.
//!
//! ```text
//! cargo run --example tool_attach
//! ```
//!
//! Connecting to a live server usually needs `PMIX_SERVER_URI*` / a URI file.
//! This example still compiles as a smoke check and exits cleanly when no
//! server is available.

use pmix::info::empty;
use pmix::tool::{
    PmixToolHandle, tool_attach_to_server, tool_finalize, tool_init, tool_is_connected,
};

fn main() {
    println!("pmix-rs tool_attach");

    let info = empty();
    let handle: PmixToolHandle = match tool_init(None, &info) {
        Ok(h) => h,
        Err(e) => {
            eprintln!("tool_init failed (no server/URI?): {e:?}");
            return;
        }
    };

    println!("tool_init ok; connected={}", tool_is_connected());

    // Attempt attach when a server identity is desired. Without a DVM this
    // typically returns an error — still useful as an API walkthrough.
    let attach_info = empty();
    match tool_attach_to_server(Some(handle.proc()), true, &attach_info) {
        Ok((_tool, server)) => {
            println!(
                "tool_attach_to_server ok; server={:?}",
                server.as_ref().map(|s| s.proc().get_rank())
            );
        }
        Err(e) => {
            println!("tool_attach_to_server: {e:?} (expected without daemon)");
        }
    }

    match tool_finalize(handle) {
        Ok(()) => println!("tool_finalize ok"),
        Err(e) => eprintln!("tool_finalize: {e:?}"),
    }

    println!("tool_attach done");
}

//! Safe Rust wrappers for PMIx Allocation and Job Control APIs.
//!
//! This module provides safe, idiomatic Rust bindings for the PMIx
//! allocation request and job control functions:
//!
//! - [`allocation_request`] — blocking allocation request
//! - [`allocation_request_nb`] — non-blocking allocation request
//! - [`job_control`] — blocking job control action (pause, resume, kill, etc.)
//! - [`job_control_nb`] — non-blocking job control action
//!
//! # C API
//! ```text
//! pmix_status_t PMIx_Allocation_request(pmix_alloc_directive_t directive,
//!                                       pmix_info_t info[], size_t ninfo,
//!                                       pmix_info_t **results, size_t *nresults);
//! pmix_status_t PMIx_Allocation_request_nb(pmix_alloc_directive_t directive,
//!                                          pmix_info_t info[], size_t ninfo,
//!                                          pmix_info_cbfunc_t cbfunc, void *cbdata);
//! ```
//!
//! # Overview
//!
//! Allocation requests allow an application to interact with the host
//! resource manager for dynamic resource management. Several broad
//! categories are supported:
//!
//! - **New allocation** — request additional resources (memory, bandwidth,
//!   compute) that are disjoint from the current allocation.
//! - **Extend** — extend the reservation on currently allocated resources,
//!   either in time or as additional resources.
//! - **Release** — return no-longer-required resources to the scheduler,
//!   including "lending" resources with the expectation of reacquiring them.
//! - **Reacquire** — reacquire resources that were previously "lent".
//!
//! # Examples
//!
//! ```ignore
//! use pmix::{allocation::*, Info, PmixAllocDirective};
//!
//! // Request a new allocation of 4 nodes with 8 CPUs each for 1 hour
//! let info = InfoBuilder::new()
//!     .build();  // add PMIX_ALLOC_NUM_NODES, PMIX_ALLOC_NUM_CPUS, etc.
//!
//! match allocation_request(PmixAllocDirective::AllocNew, &info) {
//!     Ok(results) => println!("Got {} result entries", results.len()),
//!     Err(e) => eprintln!("Allocation failed: {:?}", e),
//! }
//! ```

use std::ffi::{c_int, c_void};
use std::ptr;
use std::sync::Mutex;

use std::sync::LazyLock;

use crate::cbdata::{decode_req_id, encode_req_id};
use crate::ffi;
#[cfg(any(test, feature = "mock_ffi"))]
use crate::mock_ffi;
use crate::{Info, PmixStatus, Proc};

// ─────────────────────────────────────────────────────────────────────────────
// PmixAllocDirective — allocation directive enum
// ─────────────────────────────────────────────────────────────────────────────

/// Allocation directive that defines the behavior of an allocation request.
///
/// Corresponds to `pmix_alloc_directive_t` (`uint8_t`) from the PMIx spec.
///
/// # Spec Reference
/// PMIx Standard v4.1, Section 12.1.4 (Job Allocation Directives)
///
/// # Values
/// - [`AllocNew`] (1) — request a new, disjoint allocation.
/// - [`AllocExtend`] (2) — extend the existing allocation.
/// - [`AllocRelease`] (3) — release part of the existing allocation.
/// - [`AllocReacquire`] (4) — reacquire previously "lent" resources.
/// - [`AllocExternal`] (128) — boundary above which implementers define values.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
#[non_exhaustive]
pub enum PmixAllocDirective {
    /// `PMIX_ALLOC_NEW` — A new allocation is being requested. The resulting
    /// allocation will be disjoint (i.e., not connected in a job sense) from
    /// the requesting allocation.
    AllocNew,

    /// `PMIX_ALLOC_EXTEND` — Extend the existing allocation, either in time
    /// or as additional resources.
    AllocExtend,

    /// `PMIX_ALLOC_RELEASE` — Release part of the existing allocation.
    /// Attributes in the accompanying `pmix_info_t` array may be used to
    /// specify permanent release of the identified resources, or "lending"
    /// of those resources for some period of time.
    AllocRelease,

    /// `PMIX_ALLOC_REAQUIRE` — Reacquire resources that were previously
    /// "lent" back to the scheduler.
    AllocReacquire,

    /// `PMIX_ALLOC_EXTERNAL` (128) — A value boundary above which
    /// implementers are free to define their own directive values.
    AllocExternal,

    /// An unrecognized or future directive value.
    Unknown(u8),
}

impl PmixAllocDirective {
    /// Convert a raw `pmix_alloc_directive_t` (`u8`) into a `PmixAllocDirective`.
    pub fn from_raw(directive: u8) -> Self {
        match directive {
            1 => Self::AllocNew,
            2 => Self::AllocExtend,
            3 => Self::AllocRelease,
            4 => Self::AllocReacquire,
            128 => Self::AllocExternal,
            other => Self::Unknown(other),
        }
    }

    /// Return the raw `u8` value suitable for passing to the C API.
    pub fn to_raw(self) -> u8 {
        match self {
            Self::AllocNew => 1,
            Self::AllocExtend => 2,
            Self::AllocRelease => 3,
            Self::AllocReacquire => 4,
            Self::AllocExternal => 128,
            Self::Unknown(v) => v,
        }
    }
}

impl std::fmt::Display for PmixAllocDirective {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::AllocNew => write!(f, "ALLOC_NEW"),
            Self::AllocExtend => write!(f, "ALLOC_EXTEND"),
            Self::AllocRelease => write!(f, "ALLOC_RELEASE"),
            Self::AllocReacquire => write!(f, "ALLOC_REAQUIRE"),
            Self::AllocExternal => write!(f, "ALLOC_EXTERNAL"),
            Self::Unknown(v) => write!(f, "UNKNOWN_DIRECTIVE ({v})"),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// AllocationResults — owned wrapper for the output info array
// ─────────────────────────────────────────────────────────────────────────────

/// Owned wrapper around the `pmix_info_t` array returned by
/// `PMIx_Allocation_request`. Automatically frees the array via
/// `PMIx_Info_free` on drop.
///
/// The results contain information about the allocation outcome, such as
/// the resource manager's allocation identifier (`PMIX_ALLOC_ID`) that
/// can be used in subsequent calls (e.g., `PMIx_Spawn`).
#[derive(Debug)]
pub struct AllocationResults {
    handle: *mut ffi::pmix_info_t,
    len: usize,
}

impl AllocationResults {
    /// Number of info entries in this result set.
    pub fn len(&self) -> usize {
        self.len
    }

    /// `true` if the result set is empty.
    pub fn is_empty(&self) -> bool {
        self.len == 0
    }
}

impl Drop for AllocationResults {
    fn drop(&mut self) {
        // In mock mode, the handle may be fake/garbage. Skip FFI calls.
        #[cfg(any(test, feature = "mock_ffi"))]
        {
            if mock_ffi::is_mock_enabled() {
                self.handle = ptr::null_mut();
                self.len = 0;
                return;
            }
        }
        if !self.handle.is_null() && self.len > 0 {
            unsafe {
