/// Allocation directive — controls the behavior of `PMIx_Allocation_request`.
///
/// Maps to `pmix_alloc_directive_t` (`uint8_t`) in the C API. Currently only
/// one value is defined by the standard: `PMIX_ALLOC_DIRECTIVE` (43), which
/// indicates a hard allocation request. Future versions may add soft requests
/// or other variants.
///
/// # C API
/// `typedef uint8_t pmix_alloc_directive_t`
/// `#define PMIX_ALLOC_DIRECTIVE 43`
///
/// Use [`PmixAllocDirective::from_raw`] to convert a `pmix_alloc_directive_t`
/// received from C and [`PmixAllocDirective::to_raw`] to convert back.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
#[repr(u8)]
#[non_exhaustive]
pub enum PmixAllocDirective {
    /// `PMIX_ALLOC_DIRECTIVE` (43) — hard allocation request.
    AllocDirective = 43,

    /// An unrecognised or future directive value.
    Unknown(u8),
}

impl PmixAllocDirective {
    /// Convert a raw `pmix_alloc_directive_t` (`u8`) into a `PmixAllocDirective`.
    pub fn from_raw(directive: u8) -> Self {
        match directive {
            43 => Self::AllocDirective,
            other => Self::Unknown(other),
        }
    }

    /// Return the raw `u8` value suitable for passing to the C API.
    pub fn to_raw(self) -> u8 {
        match self {
            Self::AllocDirective => 43,
            Self::Unknown(v) => v,
        }
    }
}

impl std::fmt::Display for PmixAllocDirective {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::AllocDirective => write!(f, "ALLOC_DIRECTIVE"),
            Self::Unknown(v) => write!(f, "UNKNOWN DIRECTIVE ({v})"),
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// IOFChannelFlags — type-safe bitmask over pmix_iof_channel_t
// ─────────────────────────────────────────────────────────────────────────────

/// Newtype over the raw `pmix_iof_channel_t` (u16 bitmask).
///
/// The `pmix_iof_channel_t` defines bit-mask flags for specifying IO
/// forwarding channels. These can be bitwise OR'd together to reference
/// multiple channels.
///
/// * `PMIX_FWD_NO_CHANNELS`   (0x0000) — forward no channels.
/// * `PMIX_FWD_STDIN_CHANNEL` (0x0001) — forward stdin.
/// * `PMIX_FWD_STDOUT_CHANNEL`(0x0002) — forward stdout.
/// * `PMIX_FWD_STDERR_CHANNEL`(0x0004) — forward stderr.
/// * `PMIX_FWD_STDDIAG_CHANNEL`(0x0008) — forward stddiag, if available.
/// * `PMIX_FWD_ALL_CHANNELS`  (0x00FF) — forward all available channels.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Default)]
pub struct IOFChannelFlags(pub pmix_iof_channel_t);

impl IOFChannelFlags {
    /// `PMIX_FWD_NO_CHANNELS` (0x0000) — forward no channels.
    pub const NO_CHANNELS: Self = Self(PMIX_FWD_NO_CHANNELS as pmix_iof_channel_t);
    /// `PMIX_FWD_STDIN_CHANNEL` (0x0001) — forward stdin.
    pub const STDIN: Self = Self(PMIX_FWD_STDIN_CHANNEL as pmix_iof_channel_t);
    /// `PMIX_FWD_STDOUT_CHANNEL` (0x0002) — forward stdout.
    pub const STDOUT: Self = Self(PMIX_FWD_STDOUT_CHANNEL as pmix_iof_channel_t);
    /// `PMIX_FWD_STDERR_CHANNEL` (0x0004) — forward stderr.
    pub const STDERR: Self = Self(PMIX_FWD_STDERR_CHANNEL as pmix_iof_channel_t);
    /// `PMIX_FWD_STDDIAG_CHANNEL` (0x0008) — forward stddiag, if available.
    pub const STDDIAG: Self = Self(PMIX_FWD_STDDIAG_CHANNEL as pmix_iof_channel_t);
    /// `PMIX_FWD_ALL_CHANNELS` (0x00FF) — forward all available channels.
    pub const ALL_CHANNELS: Self = Self(PMIX_FWD_ALL_CHANNELS as pmix_iof_channel_t);

    /// Check if no channels are set.
    pub fn is_empty(self) -> bool {
        self.0 == 0
    }
    /// Check if a specific channel flag is set.
    pub fn contains(self, flag: Self) -> bool {
        (self.0 & flag.0) == flag.0
    }
    /// Return the raw `pmix_iof_channel_t` value.
    pub fn raw(self) -> pmix_iof_channel_t {
        self.0
    }
}

impl std::ops::BitOr for IOFChannelFlags {
    type Output = Self;
    fn bitor(self, rhs: Self) -> Self {
        Self(self.0 | rhs.0)
    }
}

impl std::ops::BitOrAssign for IOFChannelFlags {
    fn bitor_assign(&mut self, rhs: Self) {
        self.0 |= rhs.0;
    }
}

impl std::fmt::Display for IOFChannelFlags {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        let mut parts = Vec::new();
        if self.contains(Self::STDIN) {
            parts.push("STDIN");
        }
        if self.contains(Self::STDOUT) {
            parts.push("STDOUT");
        }
        if self.contains(Self::STDERR) {
            parts.push("STDERR");
        }
        if self.contains(Self::STDDIAG) {
            parts.push("STDDIAG");
        }
        if parts.is_empty() {
            if self.is_empty() {
                write!(f, "NO_CHANNELS")
            } else {
                write!(f, "0x{:04X}", self.0)
            }
        } else {
            write!(f, "{}", parts.join("|"))
        }
    }
}

/// All errors the builder can produce.
#[derive(Debug, PartialEq, Eq)]
pub enum BuilderError {
    /// The key string contained an interior NUL byte.
    KeyContainsNul(NulError),
    /// The key is empty (PMIx requires a non-empty key).
    KeyEmpty,
    /// The key (in bytes, *excluding* the NUL terminator) exceeds
    /// `PMIX_MAX_KEYLEN` (511).
    KeyTooLong { len: usize, maximum: usize },
    /// No value was supplied before `build()` / `build_raw()` was called.
    MissingValue,
}

impl std::fmt::Display for BuilderError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            Self::KeyContainsNul(e) => write!(f, "key contains interior NUL: {e}"),
            Self::KeyEmpty => write!(f, "key must not be empty"),
            Self::KeyTooLong { len, maximum } => {
                write!(f, "key length {len} exceeds PMIX_MAX_KEYLEN ({maximum})")
            }
            Self::MissingValue => write!(f, "no value supplied to builder"),
        }
    }
}

impl std::error::Error for BuilderError {
    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
        match self {
            Self::KeyContainsNul(e) => Some(e),
            _ => None,
        }
    }
}

impl From<NulError> for BuilderError {
    fn from(e: NulError) -> Self {
        Self::KeyContainsNul(e)
    }
}

//! Utility functions — `PMIx_Initialized`, `PMIx_Error_string`, `PMIx_Proc_state_string`,
//! `PMIx_Scope_string`, `PMIx_Persistence_string`, `PMIx_Data_range_string`,
//! `PMIx_Info_directives_string`, `PMIx_Data_type_string`, `PMIx_Alloc_directive_string`,
//! `PMIx_IOF_channel_string`, `PMIx_Job_state_string`, `PMIx_Get_attribute_string`,
//! `PMIx_Get_attribute_name`, `PMIx_Link_state_string`, `PMIx_Device_type_string`,
//! `PMIx_generate_regex`, `PMIx_generate_ppn`, `PMIx_Register_attributes`,
//! `PMIx_IOF_pull`, `PMIx_IOF_deregister`, `PMIx_IOF_push`, and related helpers.
//!
//! This module provides safe Rust wrappers around PMIx utility APIs
//! that do not fit into the lifecycle, data, or event categories.

use crate::{
    IOFChannelFlags, InfoFlags, PmixAllocDirective, PmixDataRange, PmixDataType, PmixDeviceType,
    PmixJobState, PmixLinkState, PmixPersistence, PmixProcState, PmixScope, PmixStatus, ffi,
};
use std::ffi::CStr;
use std::ptr;

// ─────────────────────────────────────────────────────────────────────────────
// PMIx_Initialized
// ─────────────────────────────────────────────────────────────────────────────

/// Returns `true` if the PMIx client has been successfully initialized.
///
/// This function only reports the internal state of the PMIx client library.
/// It does **not** verify that an active connection with the server exists,
/// nor that the server is functional.
///
/// # C API
/// `int PMIx_Initialized(void)`
///
/// # Examples
/// ```no_run
/// use pmix::utility::initialized;
///
/// if initialized() {
///     println!("PMIx is initialized");
/// } else {
///     println!("PMIx has not been initialized yet");
/// }
/// ```
pub fn initialized() -> bool {
    // SAFETY: PMIx_Initialized takes no parameters and returns a plain int.
    // It is a thread-safe read of an internal atomic flag in the PMIx library.
    // No pointers are dereferenced and no memory is allocated or freed.
    unsafe { ffi::PMIx_Initialized() != 0 }
}

// ─────────────────────────────────────────────────────────────────────────────
// PMIx_Error_string
// ─────────────────────────────────────────────────────────────────────────────

/// Returns a human-readable string description of a PMIx status code.
///
/// The returned string is owned by the PMIx library and must not be freed
/// or modified by the caller. This wrapper copies the string into a Rust
/// `String` so the caller owns the result.
///
/// # C API
/// `const char* PMIx_Error_string(pmix_status_t status)`
///
/// # Returns
/// * `Ok(String)` — the library's description of the status code.
/// * `Err(PmixStatus)` — if the C function returned a null pointer
///   (should not happen for valid PMIx status codes, but guarded
///   against for safety).
///
/// # Examples
/// ```no_run
/// use pmix::{utility::error_string, PmixError};
///
/// let status = PmixError::Success.into();
/// let desc = error_string(status).expect("valid status");
/// assert_eq!(desc, "success");
/// ```
pub fn error_string(status: PmixStatus) -> Result<String, PmixStatus> {
    let raw = status.to_raw();
    // SAFETY: PMIx_Error_string takes a single pmix_status_t and returns
    // a pointer to a static, null-terminated string owned by the library.
    // No memory is allocated or freed by this call. The returned pointer
    // is valid for the lifetime of the process (it points to read-only
    // data inside the PMIx shared library).
    let c_ptr = unsafe { ffi::PMIx_Error_string(raw) };
    if c_ptr.is_null() {
        // Should not happen for any valid pmix_status_t, but guard anyway.
        return Err(PmixStatus::from_raw(raw));
    }
    // SAFETY: The pointer is non-null and points to a valid null-terminated
    // C string owned by the PMIx library (static lifetime).
    let cstr = unsafe { std::ffi::CStr::from_ptr(c_ptr) };
    Ok(cstr.to_string_lossy().into_owned())
}

// ─────────────────────────────────────────────────────────────────────────────
// PMIx_Proc_state_string
// ─────────────────────────────────────────────────────────────────────────────

/// Returns a human-readable string description of a PMIx process state code.
///
/// The returned string is owned by the PMIx library and must not be freed
/// or modified by the caller. This wrapper copies the string into a Rust
/// `String` so the caller owns the result.
///
/// # C API
/// `const char* PMIx_Proc_state_string(pmix_proc_state_t state)`
///
/// # Returns
/// * `Ok(String)` — the library's description of the process state.
/// * `Err(PmixStatus)` — if the C function returned a null pointer
///   (should not happen for valid `pmix_proc_state_t` values, but guarded
///   against for safety).
///
/// # Examples
/// ```no_run
/// use pmix::{utility::proc_state_string, PmixProcState};
