    /// `PmixByteObject::from_slice` copies data and is independent of source.
    #[test]
    fn test_byte_object_from_slice() {
        let data = b"hello from stdin";
        let bo = PmixByteObject::from_slice(data);
        assert_eq!(bo.as_slice(), data);
        assert_eq!(bo.len(), 16);
        assert!(!bo.is_empty());
    }

