    #[test]
    fn test_byte_object_from_vec() {
        let vec = vec![1u8, 2, 3, 4, 5];
        let bo = PmixByteObject::from_vec(vec);
        assert_eq!(bo.as_slice(), &[1, 2, 3, 4, 5]);
        assert_eq!(bo.len(), 5);
    }

