        let c_ptr = bo.as_c_mut_ptr();
        assert!(!c_ptr.is_null());
        // SAFETY: c_ptr was returned by as_c_mut_ptr and has not been freed.
        unsafe { PmixByteObject::free_c_ptr(c_ptr) };
    }

