    #[test]
    fn test_error_string_various_codes() {
        let codes: Vec<i32> = vec![
            0,   // PMIX_SUCCESS
            -1,  // PMIX_ERROR
            -24, // PMIX_ERR_TIMEOUT
            -27, // PMIX_ERR_BAD_PARAM
            -33, // PMIX_ERR_NOT_FOUND
        ];
        for code in codes {
            let status = PmixStatus::from_raw(code);
            let result = error_string(status);
            assert!(
